#include <stdio.h>
#include <string.h>
#include <stdlib.h>

int reflection(int num) {
    char digits[20];
    sprintf(digits, "%d", num);
    char reflected[20] = {0};
    int j = 0;
    for (int i = 0; digits[i] != '\0'; i++) {
        int inverted = 9 - (digits[i] - '0');
        if (inverted == 0 && j == 0) {
            continue;
        }
        reflected[j++] = inverted + '0';
    }
    if (j == 0) {
        return 0;
    }
    return atoi(reflected);
}

int solve(int l, int r) {
    int best = l * reflection(l) > r * reflection(r) ? l * reflection(l) : r * reflection(r);
    int power = 0;
    while (5 * (int)pow(10, power) <= l) {
        power++;
    }
    while (5 * (int)pow(10, power) <= r) {
        int candidate = 5 * (int)pow(10, power);
        int current = candidate * reflection(candidate);
        if (current > best) {
            best = current;
        }
        power++;
    }
    return best;
}

int main() {
    int l, r;
    scanf("%d %d", &l, &r);
    printf("%d\n", solve(l, r));
    return 0;
}
